(function(){
  const map={'privacy':'mPrivacy','terms':'mTerms','disclaimer':'mDisclaimer'};
  function openM(id){const m=document.getElementById(id);if(m){m.classList.add('open');document.body.style.overflow='hidden';}}
  function closeM(m){m.classList.remove('open');if(!document.querySelector('.lmodal.open'))document.body.style.overflow='';}
  document.querySelectorAll('[data-legal]').forEach(a=>a.addEventListener('click',e=>{e.preventDefault();openM(map[a.dataset.legal]);}));
  document.querySelectorAll('.lmodal').forEach(m=>{
    m.querySelectorAll('[data-lclose]').forEach(x=>x.addEventListener('click',()=>closeM(m)));
  });
  document.addEventListener('keydown',e=>{if(e.key==='Escape'){document.querySelectorAll('.lmodal.open').forEach(closeM);}});
})();


/* ===== POP-UP CONSULTATION ENQUIRY =====
   Fires 8s after load OR at 30% scroll depth, whichever comes first.
   Returns on every page load until the visitor actually submits.
   One attempt per page load: if anything is blocking when the trigger fires,
   the attempt is cancelled outright — never queued or re-armed. */
(function(){
  const modal=document.getElementById('mConsult');if(!modal)return;
  const DONE_KEY='gm_consult_submitted';
  const DELAY=8000, SCROLL_PCT=0.08;   // 8% fires before #consult reaches the screen

  const form=document.getElementById('cform'),succ=document.getElementById('cSucc'),
        err=document.getElementById('cErr'),btn=document.getElementById('cBtn'),
        consult=document.getElementById('consult'),sbox=document.getElementById('sbox');

  const store={
    get(){try{return localStorage.getItem(DONE_KEY)==='1'}catch(e){return false}},
    set(){try{localStorage.setItem(DONE_KEY,'1')}catch(e){}}
  };

  let done=false;          // one auto-attempt per page load
  let timer=null, lastFocus=null;
  let consultInView=false;
  if(consult&&'IntersectionObserver'in window){
    new IntersectionObserver(en=>en.forEach(x=>{consultInView=x.isIntersecting}),
      {rootMargin:'-25% 0px -25% 0px'}).observe(consult);
  }

  /* every reason not to interrupt right now */
  function blocked(){
    const a=document.activeElement;
    return consultInView
      || document.querySelector('.dw.open')!==null
      || document.querySelector('.lmodal.open')!==null
      || (consult&&a&&consult.contains(a))
      || (sbox&&a&&sbox.contains(a))
      || document.querySelector('.spanel.open')!==null;
  }

  const FOCUSABLE='a[href],button:not([disabled]),input:not([disabled]),select,textarea,[tabindex]:not([tabindex="-1"])';
  function trapFocus(e){
    if(e.key!=='Tab'||!modal.classList.contains('open'))return;
    const f=[...modal.querySelectorAll(FOCUSABLE)].filter(el=>el.offsetParent!==null);
    if(!f.length)return;
    const first=f[0],last=f[f.length-1];
    if(e.shiftKey&&document.activeElement===first){e.preventDefault();last.focus()}
    else if(!e.shiftKey&&document.activeElement===last){e.preventDefault();first.focus()}
  }

  function open(auto){
    if(auto&&(done||store.get()||blocked()))return false;
    if(auto)done=true;
    lastFocus=document.activeElement;
    modal.classList.add('open');
    document.body.style.overflow='hidden';
    const first=modal.querySelector('#cName');
    if(first&&!succ.classList.contains('on'))setTimeout(()=>first.focus(),260);
    document.addEventListener('keydown',trapFocus);
    return true;
  }
  function close(){
    modal.classList.remove('open');
    if(!document.querySelector('.lmodal.open'))document.body.style.overflow='';
    document.removeEventListener('keydown',trapFocus);
    done=true;                       // dismissed stays dismissed for this view
    if(lastFocus&&lastFocus.focus)lastFocus.focus();
  }
  window.openConsultModal=()=>open(false);

  modal.querySelectorAll('[data-lclose]').forEach(x=>x.addEventListener('click',close));
  document.addEventListener('keydown',e=>{
    if(e.key==='Escape'&&modal.classList.contains('open'))close();
  });

  /* trigger: timer vs scroll depth, first one wins */
  function fire(){
    clearTimeout(timer);removeEventListener('scroll',onScrollTrigger);
    open(true);
  }
  /* Fires the moment the threshold is crossed — deliberately not debounced, so
     it appears while the visitor is still above the inline form rather than
     waiting for them to stop scrolling. */
  function onScrollTrigger(){
    const dh=document.documentElement.scrollHeight-innerHeight;
    if(dh>0&&scrollY/dh>=SCROLL_PCT)fire();
  }
  /* Landing on /#consult means they came for the inline form — don't interrupt.
     Handled here rather than in blocked(), because the scroll trigger fires on
     the way down and would otherwise beat the form onto the screen. */
  const askedForForm=location.hash==='#consult';
  if(!store.get()&&!askedForForm){
    timer=setTimeout(fire,DELAY);
    addEventListener('scroll',onScrollTrigger,{passive:true});
  }

  /* the floating pill opens it manually — always, even after submitting */
  const pill=document.getElementById('fctaBtn');
  if(pill)pill.addEventListener('click',()=>open(false));

  /* submit */
  form.addEventListener('submit',e=>{
    e.preventDefault();
    const name=document.getElementById('cName').value.trim(),
          phone=document.getElementById('cPhone').value.trim(),
          email=document.getElementById('cEmail').value.trim(),
          country=document.getElementById('cCountry').value.trim();
    const fail=m=>{err.textContent=m;err.classList.add('on')};
    if(!name||!phone||!email||!country)return fail('Please fill in your name, phone, email and country.');
    if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))return fail('Please enter a valid email address.');
    if(!document.getElementById('cConsent').checked)return fail('Please accept the Terms & Privacy Policy to continue.');
    err.classList.remove('on');
    btn.disabled=true;btn.textContent='Sending…';btn.style.opacity='.7';
    fetch('/api/consult',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({
      name,country,email,
      dialCode:modal.querySelector('.telcode').textContent,
      phone,
      message:document.getElementById('cMsg').value,
      source:'popup'
    })}).then(r=>r.json()).then(d=>{
      if(d&&d.ok){store.set();form.style.display='none';succ.classList.add('on');}
      else throw new Error(d&&d.error||'failed');
    }).catch(e2=>{
      fail((e2&&e2.message)||'Something went wrong. Please try again or WhatsApp us.');
      btn.disabled=false;btn.innerHTML='Request a Call Back';btn.style.opacity='1';
    });
  });
})();
